import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import axios from 'axios';
import Navbar from "./components/Navbar";

const cacheBusqueda = {};

function App() {
  // --- ESTADOS DE AUTENTICACIÓN ---
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [authMode, setAuthMode] = useState('login'); 
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [email, setEmail] = useState(''); 
  const [telefono, setTelefono] = useState(''); 
  const [userRole, setUserRole] = useState('vendedor');
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  // --- ESTADOS DE DATOS ---
  const [view, setView] = useState('dashboard');
  const [filtroBajoStock, setFiltroBajoStock] = useState(false); 
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  const [loading, setLoading] = useState(false);

  // --- ESTADOS DE FORMULARIO ---
  const [showForm, setShowForm] = useState(false);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: '', precio_venta: '' });

  // --- ESTADOS DE SEGURIDAD (OTP) ---
  const [twoStep, setTwoStep] = useState(false); 
  const [otp, setOtp] = useState(''); 

  const abortControllerRef = useRef(null);

  // 1. CARGA DE DATOS
  const cargarDatos = useCallback(async () => {
    setLoading(true);
    try {
      const [resStats, resProds] = await Promise.all([
        axios.get('http://localhost:5000/api/stats'),
        axios.get('http://localhost:5000/api/productos')
      ]);
      setStats(resStats.data);
      setProductos(resProds.data);
    } catch (error) { console.error("Error:", error); } 
    finally { setLoading(false); }
  }, []);

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
      const interval = setInterval(cargarDatos, 30000);
      return () => clearInterval(interval);
    }
  }, [isLoggedIn, cargarDatos]);

  // 2. BUSQUEDA CON DEBOUNCE
  const ejecutarBusqueda = useCallback(async (texto) => {
    if (texto.trim() === '') { cargarDatos(); return; }
    if (cacheBusqueda[texto]) { setProductos(cacheBusqueda[texto]); return; }
    if (abortControllerRef.current) abortControllerRef.current.abort();
    abortControllerRef.current = new AbortController();
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/buscar?q=${texto}`, { 
        signal: abortControllerRef.current.signal 
      });
      cacheBusqueda[texto] = res.data;
      setProductos(res.data);
    } catch (err) { if (err.name !== 'CanceledError') console.error(err); }
  }, [cargarDatos]);

  const optimizadaBusqueda = useMemo(() => {
    const debounce = (fn, delay) => {
      let timeout;
      return (...args) => { clearTimeout(timeout); timeout = setTimeout(() => fn(...args), delay); };
    };
    return debounce(ejecutarBusqueda, 500);
  }, [ejecutarBusqueda]);

  const handleBusquedaChange = (e) => {
    setBusqueda(e.target.value);
    optimizadaBusqueda(e.target.value);
  };

  // 3. ACCIONES DE USUARIO
  const handleLogin = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
      if (res.data.success) {
        setEmail(res.data.email);
        setTwoStep(true); 
      }
    } catch (e) { alert("Usuario o clave incorrectos"); }
  };

  const verificarOTP = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/verify-otp', { usuario, otp });
      if (res.data.success) {
        setUserRole(res.data.rol);
        setIsLoggedIn(true);
      } else { alert("Código incorrecto. Búscalo en la terminal del Servidor."); }
    } catch (e) { alert("Error de conexión"); }
  };

  const handleRegister = async () => {
    if (!usuario || !password || !email || !telefono) return alert("Faltan datos");
    try {
      await axios.post('http://localhost:5000/api/register', { email, usuario, telefono, clave: password, rol: nuevoRol });
      alert("¡Registro exitoso!");
      setAuthMode('login');
    } catch (e) { alert("Error al registrar"); }
  };

  const guardarProducto = async () => {
    try {
      await axios.post('http://localhost:5000/api/productos', {
        nombre: nuevoProd.nombre,
        stock: Number(nuevoProd.stock),
        precio_venta: Number(nuevoProd.precio_venta)
      });
      setShowForm(false);
      cargarDatos();
      setNuevoProd({ nombre: '', stock: '', precio_venta: '' });
    } catch (e) { alert("Error al guardar"); }
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Eliminar producto?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  // --- VISTA DE ACCESO (LOGIN / REGISTRO / 2FA) ---
  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#bdc3c7] flex items-center justify-center p-4 font-sans">
        <div className="bg-[#2d333b] p-10 rounded-[40px] shadow-2xl w-full max-w-sm border border-gray-700">
          {twoStep ? (
            <div className="text-center animate-in zoom-in duration-300">
              <i className="fas fa-shield-alt text-[#00c984] text-5xl mb-6"></i>
              <h2 className="text-2xl font-bold text-white mb-2 uppercase">Verificación</h2>
              <p className="text-gray-400 text-[10px] mb-8 uppercase tracking-widest">Código enviado a: {email || 'tu correo'}</p>
              <input 
                maxLength="6"
                placeholder="000000"
                className="w-full bg-[#444c56] text-white text-center text-5xl font-black py-4 rounded-3xl outline-none mb-8 tracking-[10px]"
                onChange={e => setOtp(e.target.value)}
              />
              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-4 rounded-3xl text-xl" onClick={verificarOTP}>CONFIRMAR</button>
            </div>
          ) : (
            <div className="space-y-4">
              <h2 className="text-3xl font-black text-white text-center uppercase tracking-tighter mb-6">
                {authMode === 'login' ? 'Mi Tiendita Pro' : 'Nuevo Registro'}
              </h2>
              <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-2xl outline-none" placeholder="Usuario" onChange={e => setUsuario(e.target.value)} />
              {authMode === 'register' && (
                <>
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-2xl outline-none" placeholder="Email" onChange={e => setEmail(e.target.value)} />
                  <input className="w-full bg-[#444c56] text-white px-6 py-4 rounded-2xl outline-none" placeholder="Teléfono" onChange={e => setTelefono(e.target.value)} />
                  <div className="space-y-1">
                    <p className="text-[10px] text-[#00c984] font-bold ml-2 uppercase">Tipo de cuenta</p>
                    <select 
                        className="w-full bg-[#444c56] text-white px-6 py-4 rounded-2xl outline-none appearance-none cursor-pointer border border-transparent focus:border-[#00c984]"
                        value={nuevoRol} 
                        onChange={e => setNuevoRol(e.target.value)}
                    >
                        <option value="vendedor">Vendedor</option>
                        <option value="admin">Administrador</option>
                    </select>
                  </div>
                </>
              )}
              <input type="password" title="Contraseña" className="w-full bg-[#444c56] text-white px-6 py-4 rounded-2xl outline-none" placeholder="Contraseña" onChange={e => setPassword(e.target.value)} />
              <button className="w-full bg-[#00c984] text-[#1e293b] font-black py-4 rounded-2xl shadow-lg uppercase" onClick={authMode === 'login' ? handleLogin : handleRegister}>
                {authMode}
              </button>
              <p className="text-center text-[10px] text-gray-400 font-bold uppercase cursor-pointer" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')}>
                {authMode === 'login' ? '¿No tienes cuenta? Regístrate' : 'Volver al login'}
              </p>
            </div>
          )}
        </div>
      </div>
    );
  }

  // --- VISTA PRINCIPAL (DASHBOARD + INVENTARIO) ---
  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar setView={setView} userRole={userRole} logout={() => setIsLoggedIn(false)} busqueda={busqueda} handleBusquedaChange={handleBusquedaChange} />

      {loading && <div className="h-1 w-full bg-[#00c984] fixed top-[80px] z-50 animate-pulse"></div>}

      <main className="max-w-7xl mx-auto p-4 md:p-12">
        {view === "dashboard" ? (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <h2 className="text-3xl font-black text-[#1e293b] uppercase italic tracking-tighter">Resumen del Almacén</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8 text-center">

              <div onClick={() => { setView('productos'); setFiltroBajoStock(false); }} className="bg-white p-10 border-2 rounded-[50px] shadow-xl cursor-pointer hover:scale-105 transition">
                <p className="text-xs text-slate-400 font-black uppercase mb-2 tracking-widest italic">Stock Total</p>
                <p className="text-6xl font-black text-[#1e293b]">{stats.total_productos}</p>
                <p className="text-[10px] text-blue-500 font-bold mt-2 uppercase tracking-widest">Click para ver inventario</p>
              </div>

              <div onClick={() => { setView('productos'); setFiltroBajoStock(true); }} className="bg-white p-10 border-2 rounded-[50px] shadow-xl cursor-pointer hover:scale-105 transition">
                <p className="text-xs text-red-400 font-black uppercase mb-2 tracking-widest italic">Bajo Almacén</p>
                <p className="text-6xl font-black text-red-500">{stats.bajo_stock}</p>
                <p className="text-[10px] text-red-500 font-bold mt-2 uppercase tracking-widest">Click para ver faltantes</p>
              </div>

              <div className="bg-white p-10 border-2 rounded-[50px] shadow-xl">
                <p className="text-xs text-green-400 font-black uppercase mb-2 tracking-widest italic">Capital Invertido</p>
                <p className="text-5xl font-black text-green-600">${stats.valor_inventario.toLocaleString()}</p>
              </div>
            </div>
          </div>
        ) : (
          <div className="space-y-6 animate-in fade-in duration-300">
            <div className="flex justify-between items-center">
              <div>
                <h2 className="text-3xl font-black uppercase text-[#1e293b] tracking-tighter">
                  {filtroBajoStock ? "📦 Productos por Agotarse" : "📦 Inventario Completo"}
                </h2>
                {filtroBajoStock && (
                  <button onClick={() => setFiltroBajoStock(false)} className="text-[10px] text-blue-500 font-bold uppercase underline">Mostrar todo el almacén</button>
                )}
              </div>
              <button onClick={() => setShowForm(!showForm)} className="bg-[#1e293b] text-white px-8 py-3 rounded-2xl font-black text-xs uppercase shadow-lg">
                {showForm ? 'Cerrar Panel' : '+ Agregar'}
              </button>
            </div>

            {showForm && (
              <div className="bg-white p-6 rounded-[30px] border-4 border-dashed grid grid-cols-1 md:grid-cols-4 gap-4 animate-in slide-in-from-top duration-300">
                <input className="p-4 bg-gray-50 rounded-2xl outline-none font-bold" placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} />
                <input className="p-4 bg-gray-50 rounded-2xl outline-none" placeholder="Stock" type="number" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} />
                <input className="p-4 bg-gray-50 rounded-2xl outline-none" placeholder="Precio" type="number" value={nuevoProd.precio_venta} onChange={e => setNuevoProd({...nuevoProd, precio_venta: e.target.value})} />
                <button onClick={guardarProducto} className="bg-[#00c984] text-[#1e293b] font-black rounded-2xl py-4 uppercase">Insertar</button>
              </div>
            )}

            <div className="bg-white border rounded-[40px] shadow-2xl overflow-hidden overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-gray-100 text-[10px] font-black uppercase text-gray-400 tracking-widest">
                  <tr>
                    <th className="p-6">Descripción</th>
                    <th className="p-6">Disponibilidad</th>
                    <th className="p-6">Costo Venta</th>
                    <th className="p-6 text-center">Acciones</th>
                  </tr>
                </thead>
                <tbody className="divide-y text-sm font-bold text-slate-700">
                  {productos
                    .filter(p => filtroBajoStock ? p.stock < 10 : true) 
                    .map(p => (
                    <tr key={p.id} className="hover:bg-slate-50 transition">
                      <td className="p-6 uppercase font-black text-slate-900">{p.nombre}</td>
                      <td className="p-6">
                        <span className={`px-4 py-2 rounded-full text-[10px] font-black border ${p.stock < 10 ? 'bg-red-50 text-red-600 border-red-100' : 'bg-green-50 text-green-600 border-green-100'}`}>
                          {p.stock} UNIDADES
                        </span>
                      </td>
                      <td className="p-6 text-xl font-black text-slate-800">${p.precio_venta}</td>
                      <td className="p-6 text-center">
                        <button onClick={() => eliminar(p.id)} className="text-red-300 hover:text-red-600 transition">
                          <i className="fas fa-trash-alt"></i>
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
